const method = $input.first().json.headers?.['x-forwarded-method'] || $input.first().json.method || 'GET';
if (method === 'OPTIONS') {
  $execution.respond({
    statusCode: 200,
    headers: { 'Access-Control-Allow-Origin': '*', 'Access-Control-Allow-Methods': 'POST, OPTIONS', 'Access-Control-Allow-Headers': 'Content-Type, Authorization, Accept' },
    body: ''
  });
  return [];
}
const body = $input.first().json.body || {};
const nip = body.nip || '';
const userId = body.user_id || '';
const role = body.role || 'USER';
const instansiId = body.instansi_id || '';
const action = body.action || 'login';
const sessionToken = body.session_token || '';
if (action === 'login' && !nip) {
  $execution.respond({ statusCode: 400, body: { ok: false, message: 'NIP required' } });
  return [];
}
return [{ json: { action, nip: nip.replace(/'/g,"''"), user_id: userId.replace(/'/g,"''"), role, instansi_id: instansiId.replace(/'/g,"''"), session_token: sessionToken.replace(/'/g,"''") } }];

const d = $input.first().json;
if (d.action === 'login') {
  return [{ json: { sql: `SELECT create_session('${d.nip}','${d.user_id}','${d.role}','${d.instansi_id}') AS session_token;` } }];
} else {
  return [{ json: { sql: `UPDATE auth_sessions SET is_active=false WHERE session_token='${d.session_token}';` } }];
}

const d = $input.first().json;
if (d.session_token) {
  return [{ json: { ok: true, session_token: d.session_token } }];
}
return [{ json: { ok: true, message: 'Logged out' } }];
